package com.example.easymoney.data.remote

import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

object LoanApiFactory {
    const val MOCK_BASE_URL = "https://mockapi.easymoney.dev/"

    fun create(baseUrl: String = MOCK_BASE_URL): LoanApiService {
        val logger = HttpLoggingInterceptor().apply {
            level = HttpLoggingInterceptor.Level.BODY
        }

        val okHttpClient = OkHttpClient.Builder()
            .addInterceptor(logger)
            .build()

        return Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(LoanApiService::class.java)
    }
}

package com.example.easymoney.data.remote

import com.example.easymoney.data.remote.dto.LoanPackageDto
import com.example.easymoney.data.remote.dto.LoanPackagesResponseDto
import retrofit2.http.GET
import retrofit2.http.Path
import retrofit2.http.Query

interface LoanApiService {
    @GET("loan-packages")
    suspend fun getLoanPackages(
        @Query("customerId") customerId: String? = null
    ): LoanPackagesResponseDto

    @GET("loan-packages/{id}")
    suspend fun getLoanPackageById(
        @Path("id") id: String
    ): LoanPackageDto
}

package com.example.easymoney.data.remote

import com.example.easymoney.data.remote.dto.LoanPackageDto

interface LoanRemoteDataSource {
    suspend fun fetchLoanPackages(customerId: String? = null): List<LoanPackageDto>
    suspend fun fetchLoanPackageById(id: String): LoanPackageDto
}

class LoanRemoteDataSourceImpl(
    private val apiService: LoanApiService
) : LoanRemoteDataSource {
    override suspend fun fetchLoanPackages(customerId: String?): List<LoanPackageDto> {
        return apiService.getLoanPackages(customerId).items.orEmpty()
    }

    override suspend fun fetchLoanPackageById(id: String): LoanPackageDto {
        return apiService.getLoanPackageById(id)
    }
}

package com.example.easymoney.data.remote.dto
import com.example.easymoney.domain.model.LoanPackageModel
fun LoanPackageDto.toDomain(): LoanPackageModel { return LoanPackageModel( id = id.orEmpty(), packageName = packageName.orEmpty(), tenorRange = tenorRange ?: "6,12,18,24", minAmount = minAmount ?: 0L, maxAmount = maxAmount ?: 0L, interest = interest ?: 0.0, overdueCost = overdueCost ?: 0.0, eligibleCreditScore = eligibleCreditScore ?: 0 ) }

package com.example.easymoney.data.remote.dto

import com.google.gson.annotations.SerializedName

data class LoanPackageDto(
    @SerializedName(value = "id", alternate = ["package_id"])
    val id: String? = null,
    @SerializedName(value = "package_name", alternate = ["name"])
    val packageName: String? = null,
    @SerializedName(value = "tenor_range", alternate = ["tenor"])
    val tenorRange: String? = null,
    @SerializedName(value = "min_amount", alternate = ["minimum_amount"])
    val minAmount: Long? = null,
    @SerializedName(value = "max_amount", alternate = ["maximum_amount"])
    val maxAmount: Long? = null,
    @SerializedName(value = "interest", alternate = ["interest_rate"])
    val interest: Double? = null,
    @SerializedName(value = "overdue_cost", alternate = ["late_fee"])
    val overdueCost: Double? = null,
    @SerializedName(value = "eligible_credit_score", alternate = ["credit_score"])
    val eligibleCreditScore: Int? = null
)

package com.example.easymoney.data.remote.dto

import com.google.gson.annotations.SerializedName

data class LoanPackagesResponseDto(
    @SerializedName(value = "items", alternate = ["data", "results"])
    val items: List<LoanPackageDto>? = null
)

package com.example.easymoney.data.remote.mock

import com.example.easymoney.domain.model.LoanPackageModel

class LoanMockDataSource {
    private val mockLoanPackages = listOf(
        LoanPackageModel(
            id = "1",
            packageName = "Vay Nhanh",
            tenorRange = "6,12,18,24",
            minAmount = 6_000_000L,
            maxAmount = 100_000_000L,
            interest = 12.0,
            overdueCost = 5.0,
            eligibleCreditScore = 600
        ),
        LoanPackageModel(
            id = "2",
            packageName = "Vay Linh Hoat",
            tenorRange = "3,6,9,12",
            minAmount = 3_000_000L,
            maxAmount = 50_000_000L,
            interest = 10.5,
            overdueCost = 4.0,
            eligibleCreditScore = 550
        )
    )

    fun getLoanPackages(): List<LoanPackageModel> = mockLoanPackages

    fun getLoanPackageById(id: String): LoanPackageModel? {
        return mockLoanPackages.firstOrNull { it.id == id }
    }
}

package com.example.easymoney.data.repository
import com.example.easymoney.domain.common.Resource import com.example.easymoney.domain.model.LoanPackageModel import kotlinx.coroutines.flow.Flow
interface LoanRepository { fun getLoanPackages(customerId: String? = null): Flow<Resource<List<LoanPackageModel>>> suspend fun getLoanPackageById(id: String): Resource<LoanPackageModel> }

package com.example.easymoney.data.repository

import com.example.easymoney.data.remote.LoanRemoteDataSource
import com.example.easymoney.data.remote.dto.toDomain
import com.example.easymoney.data.remote.mock.LoanMockDataSource
import com.example.easymoney.domain.common.Resource
import com.example.easymoney.domain.model.LoanPackageModel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow

class LoanRepositoryImpl(
    private val remoteDataSource: LoanRemoteDataSource,
    private val mockDataSource: LoanMockDataSource
) : LoanRepository {

    override fun getLoanPackages(customerId: String?): Flow<Resource<List<LoanPackageModel>>> = flow {
        emit(Resource.Loading)

        try {
            val remoteData = remoteDataSource.fetchLoanPackages(customerId).map { it.toDomain() }
            emit(Resource.Success(data = remoteData, isFromMock = false))
        } catch (throwable: Throwable) {
            val mockData = mockDataSource.getLoanPackages()
            if (mockData.isNotEmpty()) {
                emit(Resource.Success(data = mockData, isFromMock = true))
            } else {
                emit(Resource.Error(message = "Unable to fetch loan packages", throwable = throwable))
            }
        }
    }

    override suspend fun getLoanPackageById(id: String): Resource<LoanPackageModel> {
        return try {
            val remoteData = remoteDataSource.fetchLoanPackageById(id).toDomain()
            Resource.Success(data = remoteData, isFromMock = false)
        } catch (throwable: Throwable) {
            val mockData = mockDataSource.getLoanPackageById(id)
            if (mockData != null) {
                Resource.Success(data = mockData, isFromMock = true)
            } else {
                Resource.Error(message = "Loan package not found", throwable = throwable)
            }
        }
    }
}

package com.example.easymoney.domain.common

sealed class Resource<out T> {
    data object Loading : Resource<Nothing>()

    data class Success<T>(
        val data: T,
        val isFromMock: Boolean = false
    ) : Resource<T>()

    data class Error<T>(
        val message: String,
        val throwable: Throwable? = null,
        val data: T? = null
    ) : Resource<T>()
}

package com.example.easymoney.domain.model

data class LoanPackageModel(
    val id: String,
    val packageName: String,
    val tenorRange: String,
    val minAmount: Long,
    val maxAmount: Long,
    val interest: Double,
    val overdueCost: Double,
    val eligibleCreditScore: Int
) {
    fun getTenorList(defaultTenors: List<Int> = listOf(6, 12, 18, 24)): List<Int> {
        return try {
            tenorRange.split(",").map { it.trim().toInt() }
        } catch (_: Exception) {
            defaultTenors
        }
    }
}
